module top_module(
  input clk,
  input reset,
  input [3:0] A,
  input [3:0] B,
  output [3:0] S
);reg [3:0] unused_carry;
reg [3:0] sum;

always @ (posedge clk or negedge reset) begin
  if (!reset) begin
    unused_carry <= 4'b0;
    sum <= 4'b0;
  end else begin
    unused_carry <= {unused_carry[2:0], A[3]&B[3] | A[3]&unused_carry[3] | B[3]&unused_carry[3]};
    sum <= A + B + unused_carry;
  end
end

assign S = sum;

endmodule
